// Pull data from both upstream nodes
const accountsWrapper = $('Query Churn Signal Accounts').first().json;
const accounts = accountsWrapper.records || [];

const refundsWrapper = $input.first().json;
const refunds = refundsWrapper.records || [];

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long', month: 'long', day: 'numeric', year: 'numeric'
});

// Deduplicate accounts by Id
const accountMap = new Map();
for (const a of accounts) {
  if (!accountMap.has(a.Id)) accountMap.set(a.Id, a);
}
const uniqueAccounts = Array.from(accountMap.values());

// Group by severity
const withCancelRequest = uniqueAccounts.filter(a => a.Cancellation_or_Pause_Request_Date__c);
const critical = uniqueAccounts.filter(a => a.Health_Tier__c === 'Critical' && !a.Cancellation_or_Pause_Request_Date__c);
const atRisk   = uniqueAccounts.filter(a => a.Health_Tier__c === 'At Risk'   && !a.Cancellation_or_Pause_Request_Date__c);
const delinquent = uniqueAccounts.filter(a => a.Delinquent__c && a.Health_Tier__c !== 'Critical' && !a.Cancellation_or_Pause_Request_Date__c);
const flaggedOnly = uniqueAccounts.filter(a => a.Flagged_Status__c && !a.Delinquent__c && !a.Cancellation_or_Pause_Request_Date__c && a.Health_Tier__c !== 'Critical' && a.Health_Tier__c !== 'At Risk');

// MRR at risk
const totalMrr = uniqueAccounts.reduce((sum, a) => sum + (a.Total_Monthly_Recurring_Amount__c || 0), 0);

const lines = [];
lines.push(`🚨 *Prophet Nightly Churn Scan — ${today}*`);
lines.push(`*${uniqueAccounts.length} account${uniqueAccounts.length !== 1 ? 's' : ''} flagged | ${refunds.length} open refund request${refunds.length !== 1 ? 's' : ''} | Total MRR at risk: $${totalMrr.toLocaleString()}*`);
lines.push('');

// ── Open Refund Requests (Priority Override) ──────────────────────────────
if (refunds.length > 0) {
  lines.push(`⚠️ *Open Refund Requests — Priority Override (${refunds.length})*`);
  for (const r of refunds.slice(0, 6)) {
    const acctName = (r.Account__r && r.Account__r.Name) ? r.Account__r.Name : r.Account__c || 'Unknown';
    const ownerName = (r.Account__r && r.Account__r.Owner && r.Account__r.Owner.Name) ? r.Account__r.Owner.Name : '';
    const amt = r.Refund_Amount__c ? ` — $${Number(r.Refund_Amount__c).toLocaleString()}` : '';
    const owner = ownerName ? ` | AM: ${ownerName}` : '';
    const reason = r.Reason__c ? ` | "${r.Reason__c.slice(0, 60)}"` : '';
    lines.push(`  • *${acctName}*${amt}${owner}${reason}`);
  }
  if (refunds.length > 6) lines.push(`  • _...and ${refunds.length - 6} more refund requests_`);
  lines.push('');
}

// ── Cancellation / Pause Requests ────────────────────────────────────────
if (withCancelRequest.length > 0) {
  lines.push(`🛑 *Cancellation or Pause Request on File (${withCancelRequest.length})*`);
  for (const a of withCancelRequest.slice(0, 6)) {
    const mrr = a.Total_Monthly_Recurring_Amount__c ? `$${Number(a.Total_Monthly_Recurring_Amount__c).toLocaleString()}/mo` : 'MRR ?';
    const score = a.Health_Score__c != null ? ` | Score: ${a.Health_Score__c}/100` : '';
    const ownerName = (a.Owner && a.Owner.Name) ? a.Owner.Name : 'Unknown';
    const date = a.Cancellation_or_Pause_Request_Date__c || 'date unknown';
    lines.push(`  • *${a.Name}* | ${mrr}${score} | Requested: ${date} | AM: ${ownerName}`);
  }
  lines.push('');
}

// ── Critical Health Tier ─────────────────────────────────────────────────
if (critical.length > 0) {
  lines.push(`🔴 *Critical Health Score (${critical.length})*`);
  for (const a of critical.slice(0, 6)) {
    const mrr = a.Total_Monthly_Recurring_Amount__c ? `$${Number(a.Total_Monthly_Recurring_Amount__c).toLocaleString()}/mo` : 'MRR ?';
    const score = a.Health_Score__c != null ? ` | Score: ${a.Health_Score__c}/100` : '';
    const delinqFlag = a.Delinquent__c ? ' | 💳 Delinquent' : '';
    const ownerName = (a.Owner && a.Owner.Name) ? a.Owner.Name : 'Unknown';
    lines.push(`  • *${a.Name}* | ${mrr}${score}${delinqFlag} | AM: ${ownerName}`);
  }
  lines.push('');
}

// ── At Risk Health Tier ──────────────────────────────────────────────────
if (atRisk.length > 0) {
  lines.push(`🟡 *At Risk — Watch Closely (${atRisk.length})*`);
  for (const a of atRisk.slice(0, 8)) {
    const mrr = a.Total_Monthly_Recurring_Amount__c ? `$${Number(a.Total_Monthly_Recurring_Amount__c).toLocaleString()}/mo` : 'MRR ?';
    const score = a.Health_Score__c != null ? ` | Score: ${a.Health_Score__c}/100` : '';
    const ownerName = (a.Owner && a.Owner.Name) ? a.Owner.Name : 'Unknown';
    lines.push(`  • *${a.Name}* | ${mrr}${score} | AM: ${ownerName}`);
  }
  lines.push('');
}

// ── Delinquent Only ───────────────────────────────────────────────────────
if (delinquent.length > 0) {
  lines.push(`💳 *Delinquent (not yet Critical) (${delinquent.length})*`);
  for (const a of delinquent.slice(0, 5)) {
    const mrr = a.Total_Monthly_Recurring_Amount__c ? `$${Number(a.Total_Monthly_Recurring_Amount__c).toLocaleString()}/mo` : 'MRR ?';
    const ownerName = (a.Owner && a.Owner.Name) ? a.Owner.Name : 'Unknown';
    lines.push(`  • *${a.Name}* | ${mrr} | AM: ${ownerName}`);
  }
  lines.push('');
}

// ── Flagged Only ─────────────────────────────────────────────────────────
if (flaggedOnly.length > 0) {
  lines.push(`🚩 *Flagged for Attention (${flaggedOnly.length})*`);
  for (const a of flaggedOnly.slice(0, 5)) {
    const mrr = a.Total_Monthly_Recurring_Amount__c ? `$${Number(a.Total_Monthly_Recurring_Amount__c).toLocaleString()}/mo` : 'MRR ?';
    const ownerName = (a.Owner && a.Owner.Name) ? a.Owner.Name : 'Unknown';
    lines.push(`  • *${a.Name}* | ${mrr} | AM: ${ownerName}`);
  }
  lines.push('');
}

lines.push(`_Run *sf_get_churn_risk_accounts* in Prophet for full ranked list_`);
lines.push(`_Run *sf_get_pre_call_brief [account name]* for competitive gap analysis + do-nothing projection_`);

const alertCount = uniqueAccounts.length + refunds.length;
return [{ json: { message: lines.join('\n'), alertCount } }];
